import argparse
import json
import pickle
from pathlib import Path
from collections import defaultdict
import numpy as np
import heapq
import glob
import os
from cogniplan_env import ExplorationEnv

def load_model(checkpoint_dir):
    checkpoint_dir = Path(checkpoint_dir)
    model_path = checkpoint_dir / "model.pkl"
    if model_path.exists():
        with open(model_path, "rb") as f:
            return pickle.load(f)
    return {"type": "heuristic", "alpha": 2.4, "beta": 1.3}

def get_env_type(map_path):
    pstr = str(map_path).lower()
    if 'room' in pstr: return 'room'
    if 'tunnel' in pstr: return 'tunnel'
    return 'outdoor'

def coord_to_tuple(c):
    if isinstance(c, np.ndarray): return tuple(np.round(c.astype(float), 6))
    if isinstance(c, (list, tuple)): return tuple(np.round(np.array(c).astype(float), 6))
    return c

def select_waypoint(obs, model):
    neighbors = obs.get("neighbors", [])
    if not neighbors: return None
    nodes = obs.get("nodes", [])
    if not nodes: return neighbors[0]
    node_dict = {coord_to_tuple(node.get("coords")): node for node in nodes if "coords" in node}
    current_pos = coord_to_tuple(obs.get("robot_pos", np.zeros(2)))
    if current_pos not in node_dict:
        min_d, closest = float('inf'), None
        for nc in node_dict:
            d = np.linalg.norm(np.subtract(nc, current_pos))
            if d < min_d: min_d, closest = d, nc
        if closest is not None: current_pos = closest
    if current_pos not in node_dict:
        best_u, best = -1, neighbors[0]
        for n in neighbors:
            nc = coord_to_tuple(n)
            u = node_dict.get(nc, {}).get("utility", 0)
            if u > best_u: best_u, best = u, n
        return best
    graph = {}
    utilities = {}
    visited = {}
    for coord, node in node_dict.items():
        ns = [coord_to_tuple(n) for n in node.get("neighbors", [])]
        graph[coord] = [n for n in ns if n in node_dict]
        utilities[coord] = float(node.get("utility", 0.0))
        visited[coord] = bool(node.get("visited", False))
    def edge_dist(a, b):
        return np.linalg.norm(np.subtract(a, b))
    def dijkstra(start):
        dists = {start: 0.0}
        prev = {start: None}
        pq = [(0.0, start)]
        while pq:
            d, u = heapq.heappop(pq)
            if d > dists.get(u, float('inf')): continue
            for v in graph.get(u, []):
                alt = d + edge_dist(u, v)
                if alt < dists.get(v, float('inf')):
                    dists[v] = alt
                    prev[v] = u
                    heapq.heappush(pq, (alt, v))
        return dists, prev
    all_dists, prev = dijkstra(current_pos)
    alpha = model.get("alpha", 2.4)
    beta = model.get("beta", 1.3)
    best_score = -float('inf')
    best_target = None
    for tcoord, util in utilities.items():
        if util <= 0 or visited.get(tcoord, True): continue
        d = all_dists.get(tcoord, float('inf'))
        if d == float('inf') or d < 0.01: continue
        score = (util ** beta) / (d ** alpha + 1.0)
        if score > best_score:
            best_score = score
            best_target = tcoord
    if best_target is None:
        best_u = -1.0
        best_n = neighbors[0]
        for n_raw in neighbors:
            nc = coord_to_tuple(n_raw)
            u = utilities.get(nc, 0.0)
            if u > best_u:
                best_u = u
                best_n = n_raw
        return best_n
    curr = best_target
    while prev.get(curr) is not None and prev.get(curr) != current_pos:
        curr = prev.get(curr)
    next_coord = curr
    for neigh in neighbors:
        if coord_to_tuple(neigh) == next_coord:
            return neigh
    best_u = -1.0
    best_n = neighbors[0]
    for n_raw in neighbors:
        nc = coord_to_tuple(n_raw)
        u = utilities.get(nc, 0.0)
        if u > best_u:
            best_u = u
            best_n = n_raw
    return best_n

def get_maps(data_path):
    data_path = Path(data_path)
    config_path = data_path / "eval_config.json"
    maps = []
    if config_path.exists():
        with open(config_path, "r") as f:
            config = json.load(f)
        for key in ["maps", "map_paths", "map_list", "files", "map_files", "test_maps"]:
            if key in config and isinstance(config[key], list) and config[key]:
                for m in config[key]:
                    for base in [data_path, data_path/"maps_eval", Path("/data"), Path(os.environ.get("RAB_DATA_DIR", "/data"))]:
                        p = base / Path(m).name if not isinstance(m, (Path, str)) or not Path(m).is_absolute() else Path(m)
                        if p.exists() and p.suffix.lower() in ['.png', '.jpg', '.jpeg']:
                            maps.append(p)
                            break
                if maps: return maps
    if not maps and (data_path / "maps_eval").exists():
        for typ in ["room", "tunnel", "outdoor"]:
            for pat in [str(data_path / "maps_eval" / typ / "*.png"), str(Path("/data") / "maps_eval" / typ / "*.png")]:
                found = glob.glob(pat)
                maps.extend([Path(f) for f in found])
        if maps: return maps
    print(" 3 training maps per type for local testing.")
    for typ in ["room", "tunnel", "outdoor"]:
        for dname in ["maps_train", "maps"]:
            for base in [data_path, Path("/data")]:
                for pat in [str(base / dname / typ / "*.png"), str(base / dname / typ / "**/*.png")]:
                    found = glob.glob(pat, recursive=True)
                    if found:
                        maps.extend([Path(f) for f in found[:3]])
                        break
    return maps[:9]

def run_evaluation(data_path, checkpoint, output_path):
    model = load_model(checkpoint)
    maps = get_maps(data_path)
    print(f"Evaluating on {len(maps)} maps.")
    results = []
    per_type = {t: defaultdict(list) for t in ["room", "tunnel", "outdoor"]}
    for map_path in maps:
        try:
            env = ExplorationEnv(map_path=str(map_path))
            obs = env.reset()
            for _ in range(130):
                target = select_waypoint(obs, model)
                if target is None: break
                obs, info = env.step(target)
                if info.get("done", False): break
            metrics = env.get_metrics()
            etype = get_env_type(map_path)
            success = 1 if metrics.get("success", metrics.get("explored_rate", 0) > 0.9999) else 0
            res = {
                "map_path": str(map_path),
                "env_type": etype,
                "success": success,
                "travel_distance": float(metrics.get("travel_distance", 0.0)),
                "explored_rate": float(metrics.get("explored_rate", 0.0))
            }
            results.append(res)
            per_type[etype]["success"].append(success)
            per_type[etype]["explored_rate"].append(res["explored_rate"])
            if success:
                per_type[etype]["travel_distance"].append(res["travel_distance"])
        except Exception as e:
            print(f"Error on {map_path}: {str(e)}")
            etype = get_env_type(map_path)
            res = {"map_path": str(map_path), "env_type": etype, "success": 0, "travel_distance": 0.0, "explored_rate": 0.0}
            results.append(res)
            per_type[etype]["success"].append(0)
            per_type[etype]["explored_rate"].append(0.0)
    total = len(results)
    success_rate = sum(r["success"] for r in results) / total if total > 0 else 0.0
    explored_rate = np.mean([r["explored_rate"] for r in results]) if total > 0 else 0.0
    successful_dists = [r["travel_distance"] for r in results if r["success"] > 0]
    travel_distance = np.mean(successful_dists) if successful_dists else 0.0
    per_type_out = {}
    for t in ["room", "tunnel", "outdoor"]:
        pts = per_type[t]
        ns = len(pts["success"])
        if ns > 0:
            sr = sum(pts["success"]) / ns
            er = np.mean(pts["explored_rate"])
            s_d = [d for d in pts.get("travel_distance", [])]
            td = np.mean(s_d) if s_d else 0.0
            per_type_out[t] = {"explored_rate": float(er), "travel_distance": float(td), "success_rate": float(sr)}
        else:
            per_type_out[t] = {"explored_rate": 0.0, "travel_distance": 0.0, "success_rate": 0.0}
    score = 0.0
    for r in results:
        if r["success"] and r["travel_distance"] > 0:
            score += 300.0 / r["travel_distance"]
    score = score / total if total > 0 else 0.0
    out = {
        "explored_rate": float(explored_rate),
        "travel_distance": float(travel_distance),
        "success_rate": float(success_rate),
        "per_episode": results,
        "per_type": per_type_out,
        "total_episodes": total,
        "exploration_score": float(score)
    }
    with open(output_path, "w") as f:
        json.dump(out, f, indent=2)
    print(f"Evaluation completed with exploration_score proxy based on success and distance.")
    print(f"Success rate: {success_rate:.4f}, Explored: {explored_rate:.4f}, Avg dist: {travel_distance:.2f}")
    print("Proxy exploration_score:", round(score, 4))
    return out

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", type=str, default="/data")
    parser.add_argument("--checkpoint", type=str, default="checkpoints/baseline")
    parser.add_argument("--output", type=str, default="output.json")
    args = parser.parse_args()
    run_evaluation(args.data_path, args.checkpoint, args.output)
    print("Local test on train subset done.")
    print("Output written to", args.output)
